INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-orientation', 'morris-hauling', 'Company Orientation', 'Morris Hauling expectations, appearance, conduct, and customer service foundations.', 'orientation', 'quiz', true, 12, 1, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-orient-1', 'morris-hauling', 'tc-orientation', 'Welcome to Morris Hauling', 'Who we are and what we stand for.', ARRAY['State company mission', 'Know chain of command', 'Understand field expectations']::text[], '<p>Morris Hauling & Junk Removal serves homeowners and businesses across the region with honest pricing, careful property protection, and respectful crews.</p><p>Every employee represents the brand on every job. Punctuality, clean uniforms, and professional language are non-negotiable.</p><p>Report to your crew leader or dispatcher for daily assignments. Safety concerns escalate immediately — never wait.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-orient-2', 'morris-hauling', 'tc-orientation', 'Appearance & Conduct', 'Professional presence on customer property.', ARRAY['Meet uniform standards', 'Follow phone/social media policy on jobs']::text[], '<p>Wear company shirt, work pants, and closed-toe boots. No offensive graphics. Keep shirts tucked when lifting.</p><p>No smoking on customer property without explicit permission. Keep personal phones in pocket except for job photos or navigation.</p><p>Treat every home like your own: knock, introduce yourself, ask about floor protection, and thank the customer before leaving.</p>', 2, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-orient-3', 'morris-hauling', 'tc-orientation', 'Customer Service Basics', 'First impressions and communication.', ARRAY['Greet customers professionally', 'Explain scope before starting work']::text[], '<p>Arrive in the window promised. Call ahead if delayed more than 15 minutes.</p><p>Confirm what is included in the quote before loading. Point out items that may incur extra fees before moving them.</p><p>End every job with a walkthrough and ask if anything was missed.</p>', 3, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o1', 'morris-hauling', 'tc-orientation', 'Who do you report to for daily assignments?', '["Crew leader or dispatcher","Accounting","Random customer","Social media manager"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o2', 'morris-hauling', 'tc-orientation', 'When should you escalate a safety concern?', '["End of week","Immediately","Never","After the job"]'::jsonb, 1, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o3', 'morris-hauling', 'tc-orientation', 'Appropriate footwear on jobs includes:', '["Sandals","Closed-toe boots","Bare feet","Flip flops"]'::jsonb, 1, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o4', 'morris-hauling', 'tc-orientation', 'Personal phones on job sites should be:', '["Used freely","Left in truck only for photos/nav","For streaming music loudly","Given to customer"]'::jsonb, 1, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o5', 'morris-hauling', 'tc-orientation', 'Before loading, you should:', '["Start immediately","Confirm scope with customer","Leave without talking","Only text"]'::jsonb, 1, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o6', 'morris-hauling', 'tc-orientation', 'If running 20+ minutes late you should:', '["Say nothing","Call ahead","Skip the job","Post online"]'::jsonb, 1, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o7', 'morris-hauling', 'tc-orientation', 'Floor protection should be:', '["Skipped to save time","Offered/used per job","Customer only","Never discussed"]'::jsonb, 1, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-o8', 'morris-hauling', 'tc-orientation', 'Morris brand values include:', '["Honest pricing and respect","Hidden fees","Property damage","Rude service"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-orientation', 'morris-hauling', 'tc-orientation', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-orientation-1099', 'morris-hauling', 'tc-orientation', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-safety', 'morris-hauling', 'Workplace Safety', 'PPE, heat, winter hazards, and slip/fall prevention.', 'safety', 'quiz', true, 12, 2, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-safe-1', 'morris-hauling', 'tc-safety', 'PPE Requirements', 'Required protective equipment for field work.', ARRAY['List required PPE', 'Inspect PPE before shift']::text[], '<p>Minimum PPE: gloves, steel-toe boots, eye protection when cutting/drilling, hearing protection near loud equipment.</p><p>Hard hats when overhead hazards exist. High-vis vest when working near traffic.</p><p>Replace damaged PPE — torn gloves and cracked safety glasses do not protect you.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-safe-2', 'morris-hauling', 'tc-safety', 'Heat, Hydration & Winter', 'Weather-related illness prevention.', ARRAY['Recognize heat exhaustion', 'Dress for cold loads']::text[], '<p>Summer: drink water every 30 minutes, take shade breaks, watch for dizziness or cramps in yourself and crew.</p><p>Winter: layer clothing, watch for ice on ramps and trailer decks, keep hands warm for strap work.</p><p>Never work alone in extreme heat without check-ins.</p>', 2, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-safe-3', 'morris-hauling', 'tc-safety', 'Slip, Trip & Fall', 'Common job-site hazards.', ARRAY['Identify slip hazards', 'Use three points of contact']::text[], '<p>Wet grass, muddy driveways, and icy steps cause most field injuries. Slow down and plan your path.</p><p>Use three points of contact entering/exiting truck cab and trailer.</p><p>Clear debris from walking paths before carrying loads.</p>', 3, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s1', 'morris-hauling', 'tc-safety', 'Minimum footwear is:', '["Sandals","Steel-toe boots","Crocs","Barefoot"]'::jsonb, 1, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s2', 'morris-hauling', 'tc-safety', 'Eye protection is required when:', '["Eating lunch","Cutting or drilling","Driving only","Sleeping"]'::jsonb, 1, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s3', 'morris-hauling', 'tc-safety', 'Heat exhaustion signs include:', '["Dizziness and cramps","Extra energy only","Nothing visible","Improved focus"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s4', 'morris-hauling', 'tc-safety', 'Hydration in summer should be:', '["Once a day","About every 30 minutes","Never on jobs","Only soda"]'::jsonb, 1, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s5', 'morris-hauling', 'tc-safety', 'Three points of contact means:', '["Two hands one foot or two feet one hand","One hand only","Jump from cab","Run on ice"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s6', 'morris-hauling', 'tc-safety', 'High-vis vests are used:', '["Near traffic","Indoors only","Never","At home"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s7', 'morris-hauling', 'tc-safety', 'Damaged PPE should be:', '["Replaced","Taped and reused forever","Ignored","Shared"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-s8', 'morris-hauling', 'tc-safety', 'Icy trailer decks require:', '["Extra caution and slower movement","Running","No change","Less straps"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-safety', 'morris-hauling', 'tc-safety', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-safety-1099', 'morris-hauling', 'tc-safety', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-lifting', 'morris-hauling', 'Proper Lifting', 'Safe lifting technique, team lifts, and injury prevention.', 'lifting', 'quiz', true, 12, 3, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-lift-1', 'morris-hauling', 'tc-lifting', 'Lifting Fundamentals', 'Protect your back on every load.', ARRAY['Demonstrate proper stance', 'Know when to team lift']::text[], '<p>Feet shoulder-width, load close to body, bend knees not waist, lift with legs.</p><p>Never twist while carrying — pivot with your feet.</p><p>If over ~50 lbs awkward or above shoulders, get a partner or use equipment.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-lift-2', 'morris-hauling', 'tc-lifting', 'Equipment Aids', 'Dollies, straps, and appliance carts.', ARRAY['Select correct tool', 'Secure load on dolly']::text[], '<p>Use appliance dolly for fridges and washers. Furniture dolly for dressers and boxes.</p><p>Strap loads to dolly before stairs. Blankets prevent scratches and improve grip.</p><p>Inspect dollies for flat tires and broken straps before use.</p>', 2, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-lift-3', 'morris-hauling', 'tc-lifting', 'Injury Response', 'What to do if hurt on the job.', ARRAY['Report injuries immediately', 'Do not hide pain']::text[], '<p>Stop work if you feel sharp back pain, pop, or numbness. Tell your crew leader.</p><p>Document what happened. Morris will guide workers comp if needed.</p><p>Returning to heavy lifting before healing makes injuries worse.</p>', 3, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l1', 'morris-hauling', 'tc-lifting', 'Lift primarily with:', '["Back only","Legs","One arm twisted","Momentum"]'::jsonb, 1, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l2', 'morris-hauling', 'tc-lifting', 'When carrying, avoid:', '["Twisting at the waist","Keeping load close","Planning path","Team lifts"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l3', 'morris-hauling', 'tc-lifting', 'Team lift when load is:', '["Light and balanced","Heavy or awkward","Empty","Already on truck"]'::jsonb, 1, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l4', 'morris-hauling', 'tc-lifting', 'Appliance dolly is best for:', '["Fridges and washers","Paper clips","Fuel only","Sleeping"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l5', 'morris-hauling', 'tc-lifting', 'Before stairs with a dolly:', '["Strap the load","Run quickly","Tilt randomly","Skip straps"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l6', 'morris-hauling', 'tc-lifting', 'Sharp back pain means:', '["Stop and report","Hide it","Lift more","Leave site silently"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l7', 'morris-hauling', 'tc-lifting', 'Blankets help by:', '["Protecting surfaces and grip","Decoration only","Replacing straps","Blocking vision"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-l8', 'morris-hauling', 'tc-lifting', 'Feet should be:', '["Shoulder-width for stability","Together always","Crossed","Off ground"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-lifting', 'morris-hauling', 'tc-lifting', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-lifting-1099', 'morris-hauling', 'tc-lifting', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-appliance', 'morris-hauling', 'Appliance Removal', 'Safely removing fridges, washers, and connected appliances.', 'appliance_removal', 'quiz', true, 12, 4, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-app-1', 'morris-hauling', 'tc-appliance', 'Preparation & Disconnects', 'Power, water, and gas safety.', ARRAY['Verify utilities disconnected', 'Know when to refuse unsafe work']::text[], '<p>Customer or licensed tech must disconnect gas, water, and hardwired electric before move.</p><p>Fridges: drain and secure doors. Cap lines if required locally.</p><p>Never pull connected appliances — damage and injury risk.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-app-2', 'morris-hauling', 'tc-appliance', 'Moving Heavy Appliances', 'Weight and path planning.', ARRAY['Use team lift and dolly', 'Protect floors']::text[], '<p>Empty units first when possible. A full fridge exceeds safe solo lift.</p><p>Use ramps and plywood over soft ground. Plan door removal if needed.</p><p>Strap to dolly and truck wall — appliances are top-heavy.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a1', 'morris-hauling', 'tc-appliance', 'Gas appliances require:', '["Customer/pro disconnect before move","Yanking the line","No prep","Open flame nearby"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a2', 'morris-hauling', 'tc-appliance', 'Full refrigerators should be:', '["Emptied when possible","Solo carried always","Dragged","Left on site"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a3', 'morris-hauling', 'tc-appliance', 'Connected appliances:', '["Should not be pulled away connected","Can be ripped out","Need no planning","Are light"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a4', 'morris-hauling', 'tc-appliance', 'Top-heavy loads need:', '["Straps and careful tipping","Speed","One person","No dolly"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a5', 'morris-hauling', 'tc-appliance', 'Soft ground paths use:', '["Plywood/ramp planning","Ignoring mud","Bare wheels only","Skipping protection"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a6', 'morris-hauling', 'tc-appliance', 'Fridge doors should be:', '["Secured for transport","Left swinging open","Removed always","Taped shut only in rain"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a7', 'morris-hauling', 'tc-appliance', 'Hardwired electric requires:', '["Proper disconnect before move","Cutting live wires yourself","Guesswork","Wet hands"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-a8', 'morris-hauling', 'tc-appliance', 'Unsafe utility situation:', '["Stop and escalate","Proceed anyway","Hide from customer","Leave appliance halfway"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-appliance', 'morris-hauling', 'tc-appliance', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-appliance-1099', 'morris-hauling', 'tc-appliance', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-furniture', 'morris-hauling', 'Furniture Removal', 'Sectionals, mattresses, pool tables, safes, and bulky items.', 'furniture', 'quiz', true, 12, 5, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-furn-1', 'morris-hauling', 'tc-furniture', 'Bulky Furniture Basics', 'Sectionals, dressers, and mattresses.', ARRAY['Disassemble when needed', 'Protect walls and doors']::text[], '<p>Measure doorways and stairwells. Remove legs and doors when needed — bag hardware.</p><p>Use furniture blankets on corners. Two-person minimum for sectionals on stairs.</p><p>Mattresses: bag if required, stand on edge with two carriers.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-furn-2', 'morris-hauling', 'tc-furniture', 'Specialty Items', 'Pool tables, safes, pianos.', ARRAY['Know when specialist required', 'Never exceed crew capability']::text[], '<p>Pool tables and pianos often need pros — confirm with dispatch before promising.</p><p>Small safes may need appliance dolly and 3+ crew. Floor protection critical.</p><p>If customer understates weight, stop and re-quote before damage occurs.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f1', 'morris-hauling', 'tc-furniture', 'Before moving large furniture:', '["Measure path and doors","Rush in blind","Skip blankets","One person only"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f2', 'morris-hauling', 'tc-furniture', 'Sectionals on stairs need:', '["Two+ people","Solo carry","Dragging","No planning"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f3', 'morris-hauling', 'tc-furniture', 'Removed hardware should be:', '["Bagged and labeled","Lost","Left on lawn","Thrown away"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f4', 'morris-hauling', 'tc-furniture', 'Pool tables often require:', '["Specialist/disassembly plan","Solo tip","No quote change","Ignoring slate weight"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f5', 'morris-hauling', 'tc-furniture', 'Underestimated weight means:', '["Stop and re-quote","Damage property silently","Abandon customer","Hide damage"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f6', 'morris-hauling', 'tc-furniture', 'Mattresses on stairs:', '["Two carriers, controlled edge carry","Fold in half always","Drag","Throw"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f7', 'morris-hauling', 'tc-furniture', 'Wall protection uses:', '["Blankets and corner guards","Bare metal","Speed only","Nothing"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-f8', 'morris-hauling', 'tc-furniture', 'Pianos should be:', '["Confirmed with dispatch before promising","Always included free","Dropped","Rolled without equipment"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-furniture', 'morris-hauling', 'tc-furniture', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-furniture-1099', 'morris-hauling', 'tc-furniture', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-trailer', 'morris-hauling', 'Trailer Loading', 'Weight distribution, tongue weight, stacking, and customer property.', 'trailer_loading', 'quiz', true, 12, 6, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-trl-1', 'morris-hauling', 'tc-trailer', 'Load Planning', 'Balance and tongue weight.', ARRAY['Place heavy items low and forward', 'Avoid rear-heavy loads']::text[], '<p>Heaviest items go low, centered over axles, slightly forward of center.</p><p>Too much weight at rear causes sway; too much tongue weight overloads hitch.</p><p>Distribute side-to-side — don''t stack all weight on one fender.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-trl-2', 'morris-hauling', 'tc-trailer', 'Stacking & Customer Property', 'Protecting loads and surroundings.', ARRAY['Stack stable', 'Protect driveway and lawn']::text[], '<p>Build stable layers — heavy base, lighter top. Fill voids so nothing shifts.</p><p>Use plywood under dollies on soft driveways. Pick up stray debris before leaving.</p><p>Never overload trailer GVWR — check placard.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr1', 'morris-hauling', 'tc-trailer', 'Heaviest items go:', '["Low over axles, slightly forward","High at rear","Roof only","One side only"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr2', 'morris-hauling', 'tc-trailer', 'Rear-heavy trailers:', '["Can sway dangerously","Are always safer","Need no straps","Improve MPG only"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr3', 'morris-hauling', 'tc-trailer', 'GVWR means:', '["Max rated trailer weight","Tire pressure","Fuel level","Driver age"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr4', 'morris-hauling', 'tc-trailer', 'Void spaces in load should be:', '["Filled to prevent shift","Left empty always","Ignored","Filled with people"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr5', 'morris-hauling', 'tc-trailer', 'Soft driveways need:', '["Plywood/path protection","Spinning tires","Heavy concentration in one spot","Nothing"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr6', 'morris-hauling', 'tc-trailer', 'Side-to-side weight should be:', '["Balanced","All on left","All on right","Random"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr7', 'morris-hauling', 'tc-trailer', 'Before leaving site:', '["Walk property for stray debris","Speed away","Leave doors open","Skip customer"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-tr8', 'morris-hauling', 'tc-trailer', 'Tongue weight too high:', '["Overloads hitch/vehicle","Improves braking only","Is always fine","Means empty trailer"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-trailer', 'morris-hauling', 'tc-trailer', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-trailer-1099', 'morris-hauling', 'tc-trailer', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-securement', 'morris-hauling', 'Load Securement', 'Straps, nets, tarps, and retighten checks.', 'securement', 'quiz', true, 12, 7, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-sec-1', 'morris-hauling', 'tc-securement', 'Straps & Nets', 'DOT-style securement basics.', ARRAY['Apply ratchet straps correctly', 'Use angle and tension']::text[], '<p>Minimum four points on large loads. Straps at 45° angles when possible.</p><p>Protect strap webbing from sharp edges with blankets or edge protectors.</p><p>Ratchet until snug — not so tight you crush furniture unnecessarily.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-sec-2', 'morris-hauling', 'tc-securement', 'En Route Checks', 'Retighten after first miles.', ARRAY['Stop and check within 5–10 miles', 'Re-tighten after bumps']::text[], '<p>Loads settle — recheck straps after leaving customer and after first highway segment.</p><p>Tarps and nets: verify hooks and grommets. Replace frayed straps immediately.</p><p>If anything moves, stop safely and re-secure before continuing.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se1', 'morris-hauling', 'tc-securement', 'Large loads need:', '["Multiple strap points","One bungee","Hope","No straps"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se2', 'morris-hauling', 'tc-securement', 'Sharp edges require:', '["Edge protection for straps","Bare metal on webbing","Cutting straps","Ignoring"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se3', 'morris-hauling', 'tc-securement', 'First retighten check within:', '["5–10 miles of departure","100 miles only","Never","Next week"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se4', 'morris-hauling', 'tc-securement', 'Frayed straps:', '["Replace immediately","Use anyway","Tie in knot only","Hide"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se5', 'morris-hauling', 'tc-securement', 'If load shifts while driving:', '["Stop safely and re-secure","Speed up","Ignore","Film it"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se6', 'morris-hauling', 'tc-securement', 'Strap angle ideal is often:', '["About 45 degrees","Vertical only","Horizontal only","Zero tension"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se7', 'morris-hauling', 'tc-securement', 'Nets and tarps need:', '["Verified hooks/grommets","One corner loose","No checks","Wind only"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-se8', 'morris-hauling', 'tc-securement', 'Ratchet tension should be:', '["Snug without crushing needlessly","Maximum always","Loose","Removed on highway"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-securement', 'morris-hauling', 'tc-securement', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-securement-1099', 'morris-hauling', 'tc-securement', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-driving', 'morris-hauling', 'Defensive Driving', 'Backing, spotters, weather, trailer turning, pre/post-trip.', 'driving', 'quiz', true, 24, 8, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-drv-1', 'morris-hauling', 'tc-driving', 'Backing & Spotters', 'Never back blind with trailer.', ARRAY['Use spotter every time', 'Hand signals agreement']::text[], '<p>Get out and look (GOAL) before backing in tight areas. Spotter visible in mirror always.</p><p>Agree on hand signals before moving. Stop if you lose sight of spotter.</p><p>Take wide turns — trailer cuts inside.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-drv-2', 'morris-hauling', 'tc-driving', 'Pre & Post Trip', 'Daily vehicle walkaround.', ARRAY['Check tires, lights, hitch', 'Report defects before roll']::text[], '<p>Pre-trip: tires, lights, mirrors, hitch pin, safety chains, brake lights with trailer plugged.</p><p>Post-trip: note new damage, fluid leaks, tire issues in fleet log.</p><p>Weather: increase following distance in rain; avoid sudden lane changes with trailer.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d1', 'morris-hauling', 'tc-driving', 'GOAL stands for:', '["Get Out And Look","Go On All Lanes","Gas Only At Lunch","None"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d2', 'morris-hauling', 'tc-driving', 'Trailer turns:', '["Cut inside — go wide","Same as car","Sharper than car","Need no adjustment"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d3', 'morris-hauling', 'tc-driving', 'If spotter not visible:', '["Stop immediately","Speed up","Guess","Honk continuously"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d4', 'morris-hauling', 'tc-driving', 'Pre-trip includes:', '["Hitch, chains, lights","Only fuel","Skipping tires","Interior detail only"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d5', 'morris-hauling', 'tc-driving', 'Rain with trailer means:', '["More following distance","Tailgate","No change","Disable brakes"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d6', 'morris-hauling', 'tc-driving', 'New vehicle damage:', '["Log and report","Hide","Blame customer always","Ignore"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d7', 'morris-hauling', 'tc-driving', 'Safety chains are:', '["Required backup connection","Optional decoration","Removed on highway","For aesthetics"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-d8', 'morris-hauling', 'tc-driving', 'Hand signals should be:', '["Agreed before backing","Random","Ignored","Only at night"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-driving', 'morris-hauling', 'tc-driving', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-driving-1099', 'morris-hauling', 'tc-driving', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-equipment', 'morris-hauling', 'Equipment Usage', 'Dollies, straps, blankets, ramps, winch, and power tools.', 'equipment', 'quiz', true, 12, 9, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-eq-1', 'morris-hauling', 'tc-equipment', 'Hand Equipment', 'Dollies, ramps, blankets.', ARRAY['Inspect before use', 'Return clean and functional']::text[], '<p>Check dollies for broken straps and flat tires. Ramps rated for load — never exceed capacity.</p><p>Blankets fold and store dry. Wet blankets mildew in truck.</p><p>Report damage at end of shift — next crew depends on it.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-eq-2', 'morris-hauling', 'tc-equipment', 'Power Tools & Winch', 'Safe operation only if trained.', ARRAY['PPE for cutting', 'Winch line safety']::text[], '<p>Eye and hearing protection for saws and drivers. Clear area of bystanders.</p><p>Winch: stand clear of line under tension. Use hooks and rated points only.</p><p>Unplug batteries when storing. No improvised blades or bits.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e1', 'morris-hauling', 'tc-equipment', 'Damaged dollies should be:', '["Reported before next use","Hidden","Used anyway","Thrown in load"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e2', 'morris-hauling', 'tc-equipment', 'Ramp capacity:', '["Must not be exceeded","Is optional","Doubles with speed","Ignores weight"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e3', 'morris-hauling', 'tc-equipment', 'Wet blankets should be:', '["Dried before storage","Left balled wet","Discarded always","Burned on site"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e4', 'morris-hauling', 'tc-equipment', 'Winch line under tension:', '["Stand clear","Stand over it","Wrap around hand","Cut it"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e5', 'morris-hauling', 'tc-equipment', 'Power cutting requires:', '["Eye/hearing protection","No PPE","Crowd close by","Wet hands"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e6', 'morris-hauling', 'tc-equipment', 'Batteries on tools:', '["Removed for storage when policy says","Left on forever","In rain open","Given to customer"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e7', 'morris-hauling', 'tc-equipment', 'Equipment return expectation:', '["Clean and functional","Broken silently","Missing okay","Customer keeps it"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-e8', 'morris-hauling', 'tc-equipment', 'Improvised blades/bits:', '["Not allowed","Encouraged","Required","Safer"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-equipment', 'morris-hauling', 'tc-equipment', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-equipment-1099', 'morris-hauling', 'tc-equipment', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-customer', 'morris-hauling', 'Customer Service', 'Greeting, floors, complaints, upsell, payment, photos, reviews.', 'customer_service', 'quiz', false, 12, 10, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-cs-1', 'morris-hauling', 'tc-customer', 'On-Site Excellence', 'Every touchpoint matters.', ARRAY['Professional greeting', 'Floor protection offer']::text[], '<p>Knock, smile, introduce team and company. Confirm quote scope in customer words.</p><p>Offer floor runners in homes. Shoe covers when requested.</p><p>Keep language positive — never argue on site.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-cs-2', 'morris-hauling', 'tc-customer', 'Upsell, Payment & Reviews', 'Ethical revenue and closing.', ARRAY['Offer additional items professionally', 'Collect payment per policy']::text[], '<p>If customer points at more junk, offer revised price before loading extras.</p><p>Payment: follow office policy — card, check, or invoice as quoted.</p><p>Ask happy customers for Google review — show QR if provided.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c1', 'morris-hauling', 'tc-customer', 'On arrival you should:', '["Introduce team and confirm scope","Start loading silent","Honk only","Leave"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c2', 'morris-hauling', 'tc-customer', 'Floor protection:', '["Offer runners/covers","Never mention","Damage floors","Skip always"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c3', 'morris-hauling', 'tc-customer', 'Customer wants more items loaded:', '["Re-quote before loading","Load free","Refuse rudely","Hide fees"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c4', 'morris-hauling', 'tc-customer', 'On-site disputes:', '["Stay calm, call dispatcher","Yell","Walk off","Post online live"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c5', 'morris-hauling', 'tc-customer', 'Payment collection follows:', '["Office/quote policy","Personal preference","Cash only always hidden","Skip"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c6', 'morris-hauling', 'tc-customer', 'Happy customers may be asked for:', '["Google review","Social media fight","Free work next week","Nothing ever"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c7', 'morris-hauling', 'tc-customer', 'Professional language means:', '["Positive and respectful","Slang insults","Ignoring customer","Arguing"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-c8', 'morris-hauling', 'tc-customer', 'Before leaving:', '["Walkthrough with customer","Drive away fast","Leave mess","Skip goodbye"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-route', 'morris-hauling', 'Route Procedures', 'Clock in through yard, stops, dump, clock out.', 'route', 'quiz', true, 12, 11, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-rt-1', 'morris-hauling', 'tc-route', 'Start of Day', 'Clock in to yard routine.', ARRAY['Clock in on time', 'Pre-trip and load-out']::text[], '<p>Clock in via employee portal or timeclock when starting paid time.</p><p>Yard: fuel, equipment check, review route with leader. Don''t roll without dispatch release.</p><p>Verify dump tickets and landfill hours for the day.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-rt-2', 'morris-hauling', 'tc-route', 'Stops, Dump & Clock Out', 'Executing the route.', ARRAY['Job order efficiency', 'Proper dump documentation']::text[], '<p>Follow dispatch order unless re-routed. Mark job complete in system with photos if required.</p><p>Dump only at approved facilities. Keep tickets for office.</p><p>Clock out after truck secured, equipment stowed, and paperwork submitted.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r1', 'morris-hauling', 'tc-route', 'Paid time starts with:', '["Proper clock in","First customer only","Lunch","Never recording"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r2', 'morris-hauling', 'tc-route', 'Before rolling from yard:', '["Dispatch release and pre-trip","Immediate highway","Skip fuel","No equipment check"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r3', 'morris-hauling', 'tc-route', 'Dump tickets:', '["Kept for office","Thrown away","Given to customer","Burned"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r4', 'morris-hauling', 'tc-route', 'Job order changes come from:', '["Dispatcher/leader","Random choice","Customer yelling","Social media"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r5', 'morris-hauling', 'tc-route', 'Approved dumps only means:', '["No illegal dumping","Any field okay","Customer backyard","River"]'::jsonb, 0, NULL, 5);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r6', 'morris-hauling', 'tc-route', 'End of day clock out after:', '["Truck secured and paperwork done","Leaving load loose","Mid-route","Never"]'::jsonb, 0, NULL, 6);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r7', 'morris-hauling', 'tc-route', 'Required job photos:', '["Taken when policy requires","Never","Only selfies","Customer house only"]'::jsonb, 0, NULL, 7);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-r8', 'morris-hauling', 'tc-route', 'Landfill hours should be:', '["Verified before route","Ignored","Assumed 24h","Guess"]'::jsonb, 0, NULL, 8);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-route', 'morris-hauling', 'tc-route', 'w2', true);
INSERT INTO public.training_course_assignments (id, company_id, course_id, employment_type, is_required) VALUES ('tca-tc-route-1099', 'morris-hauling', 'tc-route', '1099', true);
INSERT INTO public.training_courses (id, company_id, name, description, category, course_type, is_required, expiration_months, sort_order, passing_score_percent, max_quiz_attempts, requires_lesson_completion) VALUES ('tc-emergency', 'morris-hauling', 'Emergency Procedures', 'Accident, injury, 911, fire, and property damage response.', 'emergency', 'quiz', true, 12, 12, 80, 3, true);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-em-1', 'morris-hauling', 'tc-emergency', 'Injury & Medical', 'When someone is hurt.', ARRAY['Call 911 when needed', 'Notify supervisor immediately']::text[], '<p>Life-threatening: call 911 first, then supervisor. Do not move seriously injured unless immediate danger.</p><p>Minor cuts: first aid kit, gloves, report in incident log same day.</p><p>Workers comp paperwork starts with timely reporting — delays hurt claims.</p>', 1, 30);
INSERT INTO public.training_lessons (id, company_id, course_id, title, overview, objectives, content_html, sort_order, min_read_seconds) VALUES ('tl-em-2', 'morris-hauling', 'tc-emergency', 'Accident, Fire & Property Damage', 'Vehicle and customer property events.', ARRAY['Secure scene', 'Document with photos']::text[], '<p>Accident: hazards on, call police if injuries or major damage. Exchange info, photos, no fault admissions.</p><p>Fire: evacuate, 911, extinguish only if trained and safe.</p><p>Customer property damage: stop, tell customer and dispatcher, photo document before leaving.</p>', 2, 30);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-em1', 'morris-hauling', 'tc-emergency', 'Life-threatening injury:', '["911 then supervisor","Finish job first","Hide","Post video"]'::jsonb, 0, NULL, 1);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-em2', 'morris-hauling', 'tc-emergency', 'Serious injury movement:', '["Don''t move unless immediate danger","Always drag","For photo","Ignore"]'::jsonb, 0, NULL, 2);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-em3', 'morris-hauling', 'tc-emergency', 'Vehicle accident with injuries:', '["Call police","Leave scene","Delete evidence","Argue on road"]'::jsonb, 0, NULL, 3);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-em4', 'morris-hauling', 'tc-emergency', 'At accident scene admit fault:', '["Avoid — exchange info and photos","Always yell guilty","Run","Blame customer always"]'::jsonb, 0, NULL, 4);
INSERT INTO public.training_quiz_questions (id, company_id, course_id, question, options, correct_index, explanation, sort_order) VALUES ('tq-em5', 'morris-hauling', 'tc-emergency', 'Fire response:', '["Evacuate and call 911","Hide in truck","Continue loading","Film only"]'::jsonb, 0, NULL, 5);
